agent_output:
{
  "executive_summary": "Decompose the courier platform monolith into 5 bounded contexts mapped to 6 deployable services. The decomposition follows domain boundaries, not technical layers, and is sequenced to extract the highest-risk seam (location tracking at 5K writes/sec) and the highest-consequence seam (payments with strict consistency) as independent services first. An 8-engineer team with moderate operational maturity should NOT attempt a big-bang migration — extract one service at a time over 3-4 quarters, using the Strangler Fig pattern against the existing monolith.",

  "architecture": {
    "components": [
      {
        "name": "Order Service",
        "responsibility": "Order lifecycle: placement, state machine (placed → assigned → picked-up → in-transit → delivered → completed), cancellation. Owns the order aggregate and orchestrates cross-service workflows via domain events.",
        "boundaries": "Owns orders table. Does NOT own courier assignment logic or payment execution — delegates via events/commands."
      },
      {
        "name": "Courier Service",
        "responsibility": "Courier profiles, availability management, assignment algorithm, and route optimization. Consumes order-placed events to trigger assignment. Publishes courier-assigned events.",
        "boundaries": "Owns courier profiles and assignment logic. Does NOT own raw location data — consumes location snapshots from Location Service for routing decisions."
      },
      {
        "name": "Location Service",
        "responsibility": "Ingests real-time GPS pings (5K writes/sec peak), stores time-series location data, exposes last-known-position queries and location-stream subscriptions via WebSocket/SSE.",
        "boundaries": "Owns all raw location data. Append-only write model. No business logic beyond geofence triggers (e.g., courier-near-pickup, courier-near-dropoff events). Optimized for write throughput — separate data store from OLTP services."
      },
      {
        "name": "Payment Service",
        "responsibility": "Payment authorization, capture, refunds, ledger entries. Enforces strict transactional consistency within its boundary. Integrates with external payment gateway (Stripe/Adyen).",
        "boundaries": "Owns payment and ledger tables. Processes payments idempotently. Never exposes raw payment credentials. All mutations go through its API — no shared database access."
      },
      {
        "name": "Notification Service",
        "responsibility": "Fan-out of customer and courier communications across email, SMS, and push channels. Template management. Delivery tracking and retry. Consumes domain events from all other services.",
        "boundaries": "Owns notification templates and delivery logs. Stateless with respect to business domain — purely reactive. No business decisions."
      },
      {
        "name": "Customer Service",
        "responsibility": "Customer registration, authentication, profile management, preferences, address book.",
        "boundaries": "Owns customer identity and profile data. Other services reference customers by opaque customer_id only."
      }
    ],
    "interfaces": [
      {
        "from": "Order Service",
        "to": "Courier Service",
        "contract": "Domain event: OrderPlaced { order_id, pickup_location, dropoff_location, time_constraints }",
        "coupling_type": "async-event (loose)"
      },
      {
        "from": "Courier Service",
        "to": "Order Service",
        "contract": "Domain event: CourierAssigned { order_id, courier_id, estimated_pickup_time }",
        "coupling_type": "async-event (loose)"
      },
      {
        "from": "Location Service",
        "to": "Courier Service",
        "contract": "Query API: GET /couriers/{id}/location → { lat, lng, timestamp, heading, speed }. Also publishes GeofenceTriggered events.",
        "coupling_type": "sync-query + async-event (moderate)"
      },
      {
        "from": "Order Service",
        "to": "Payment Service",
        "contract": "Command: AuthorizePayment { order_id, amount, currency, idempotency_key } → { payment_id, status }. Synchronous call — order placement requires payment auth before confirmation.",
        "coupling_type": "sync-command (tight, intentional)"
      },
      {
        "from": "Order Service",
        "to": "Notification Service",
        "contract": "Domain events: OrderConfirmed, OrderPickedUp, OrderDelivered → Notification Service subscribes and renders appropriate templates.",
        "coupling_type": "async-event (loose)"
      },
      {
        "from": "Location Service",
        "to": "Notification Service",
        "contract": "Domain event: CourierNearDropoff { order_id, eta_seconds } → triggers 'arriving soon' push notification.",
        "coupling_type": "async-event (loose)"
      },
      {
        "from": "Customer Service",
        "to": "Order Service",
        "contract": "Query API: GET /customers/{id}/profile for address resolution during order placement. Thin, cacheable.",
        "coupling_type": "sync-query (moderate, cacheable)"
      }
    ],
    "data_flow": "1) Customer places order → Order Service validates, calls Payment Service synchronously for auth hold → publishes OrderPlaced event. 2) Courier Service consumes OrderPlaced, queries Location Service for nearby available couriers, runs assignment algorithm, publishes CourierAssigned. 3) Order Service updates state on CourierAssigned. 4) Courier app sends GPS pings to Location Service at 10s intervals. Location Service writes to time-series store and evaluates geofences. 5) GeofenceTriggered events (near-pickup, near-dropoff) flow to Order Service for state transitions and Notification Service for customer alerts. 6) On delivery confirmation, Order Service publishes OrderDelivered → Payment Service captures the authorized amount, Notification Service sends receipt.",
    "patterns_used": [
      {
        "pattern": "Strangler Fig",
        "rationale": "8-person team cannot safely rewrite and operate 6 services simultaneously. Extract one service at a time behind the existing monolith's API gateway, routing traffic incrementally."
      },
      {
        "pattern": "Domain Events via Message Broker",
        "rationale": "Primary integration mechanism. Reduces temporal coupling between services. Enables independent deployment — the core requirement. Use a durable broker (e.g., Kafka or RabbitMQ with persistence) for at-least-once delivery."
      },
      {
        "pattern": "CQRS (Location Service only)",
        "rationale": "Location data is high-write (5K/s), low-read-complexity. Separate the write path (append to time-series DB) from the read path (last-known-position cache, geofence evaluation). No need for CQRS in other services."
      },
      {
        "pattern": "Idempotent Receivers",
        "rationale": "All event consumers and the Payment Service API must be idempotent. At-least-once delivery + network retries make this non-negotiable."
      },
      {
        "pattern": "Database-per-Service",
        "rationale": "Each service owns its data store. This is the prerequisite for independent deployability. No shared databases."
      },
      {
        "pattern": "Saga (Choreography-based)",
        "rationale": "Order placement spans Order + Payment. Use a choreography saga: Order Service emits events, Payment Service reacts, compensating events handle failures. Avoids a central orchestrator for this 2-step flow. If workflows grow more complex (3+ steps), revisit with an orchestration saga."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: order_id; entities: OrderLineItem; values: Address, TimeWindow; invariants: valid state transitions, payment authorized before confirmation)"
        ]
      },
      {
        "name": "Courier Operations",
        "classification": "core",
        "aggregates": [
          "Courier (root: courier_id; entities: CourierShift; values: VehicleType, ServiceZone; invariants: courier can only be assigned to one active order)",
          "Assignment (root: assignment_id; values: PickupETA, RouteGeometry; invariants: assignment requires available courier in zone)"
        ]
      },
      {
        "name": "Location Tracking",
        "classification": "supporting",
        "aggregates": [
          "CourierLocation (root: courier_id; values: GeoPoint, Timestamp, Heading, Speed; note: not a traditional aggregate — append-only stream with latest-snapshot materialized view)",
          "Geofence (root: geofence_id; values: GeoPolygon, TriggerType; invariants: geofence must be associated with active order)"
        ]
      },
      {
        "name": "Payments",
        "classification": "core",
        "aggregates": [
          "Payment (root: payment_id; values: Money, PaymentMethod; invariants: capture ≤ authorized amount, refund ≤ captured amount, all mutations idempotent via idempotency_key)",
          "LedgerEntry (root: entry_id; values: Money, EntryType, Timestamp; invariants: double-entry balancing)"
        ]
      },
      {
        "name": "Notifications",
        "classification": "generic",
        "aggregates": [
          "NotificationRequest (root: notification_id; values: Channel, Template, RecipientRef; invariants: at-least-once delivery, deduplication by correlation_id)"
        ]
      },
      {
        "name": "Customer Identity",
        "classification": "supporting",
        "aggregates": [
          "Customer (root: customer_id; entities: SavedAddress; values: ContactInfo, Preferences; invariants: unique email/phone)"
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Courier Operations",
        "relationship": "Customer-Supplier. Order Management publishes OrderPlaced; Courier Operations conforms to the event schema but owns its own assignment model."
      },
      {
        "upstream": "Order Management",
        "downstream": "Payments",
        "relationship": "Customer-Supplier with synchronous dependency. Order Service is customer; Payment Service supplies authorization. Payment Service owns the payment model — Order Service conforms to its API contract."
      },
      {
        "upstream": "Location Tracking",
        "downstream": "Courier Operations",
        "relationship": "Open Host Service. Location Service exposes a published language (lat/lng/timestamp) that Courier Operations consumes for routing. No model pollution."
      },
      {
        "upstream": "Order Management",
        "downstream": "Notifications",
        "relationship": "Customer-Supplier. Notifications is a conformist — it accepts whatever event schemas upstream services publish and maps them to templates."
      },
      {
        "upstream": "Location Tracking",
        "downstream": "Notifications",
        "relationship": "Customer-Supplier. Geofence events trigger delivery-approaching notifications."
      },
      {
        "upstream": "Customer Identity",
        "downstream": "Order Management",
        "relationship": "Shared Kernel (thin). Order Management caches customer_id + delivery address. Minimal coupling — only identity reference crosses the boundary."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Synchronous call from Order Service to Payment Service for authorization",
      "gains": "Strong consistency guarantee — order is never confirmed without payment auth. Simpler failure handling for the customer-facing flow.",
      "sacrifices": "Temporal coupling — Order Service availability depends on Payment Service availability. Adds latency to order placement.",
      "alternatives_considered": [
        "Async payment auth via events — rejected because customers expect immediate order confirmation, and eventual consistency here creates a confusing UX where an order is 'placed' but may later fail payment.",
        "Saga with reservation pattern — viable but over-engineered for a 2-step flow. Revisit if more steps are added."
      ]
    },
    {
      "decision": "Separate Location Service from Courier Service",
      "gains": "Allows independent scaling of the write-heavy location pipeline (5K/s) without affecting the courier assignment logic. Different data store technology (time-series DB vs relational). Independent deployment per requirements.",
      "sacrifices": "Additional service to operate. Network hop for courier assignment to query locations. 8-person team now has 6 services.",
      "alternatives_considered": [
        "Keep location tracking inside Courier Service — rejected because the 5K writes/sec workload has fundamentally different scaling characteristics (append-only, time-series) vs. courier CRUD/assignment (relational, transactional). Coupling them defeats the deployment independence goal."
      ]
    },
    {
      "decision": "Choreography-based sagas over orchestration",
      "gains": "No central orchestrator to build/maintain. Services are more autonomous. Simpler for 2-3 step flows.",
      "sacrifices": "Harder to reason about long-running workflows. Debugging distributed flows requires good tracing.",
      "alternatives_considered": [
        "Orchestration saga (e.g., Temporal/Step Functions) — deferred until workflows exceed 3 steps or team reports difficulty debugging choreographed flows."
      ]
    },
    {
      "decision": "6 services for 8 engineers",
      "gains": "Clean domain boundaries. Independent deployability. Right-sized services.",
      "sacrifices": "Ratio of ~1.3 engineers per service is tight. Operational overhead is real: 6 CI pipelines, 6 deployment configs, distributed tracing, per-service monitoring.",
      "alternatives_considered": [
        "Fewer services (merge Customer into Order, merge Notification into a shared lib) — viable near-term. Customer Service could stay in the monolith longer since it has low change velocity.",
        "Modular monolith as intermediate step — strong contender. Extract Location and Payment first (highest independent scaling/consistency needs), keep the rest as well-separated modules in the monolith. Recommended as Phase 1."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Notification channels",
      "evolution_path": "Notification Service is purely reactive and channel-agnostic internally. Adding new channels (WhatsApp, in-app) requires only a new channel adapter — no changes to upstream services."
    },
    {
      "area": "Assignment algorithm",
      "evolution_path": "Courier assignment logic is isolated in its own service. Can evolve from simple nearest-courier to ML-based optimization without touching Order or Location services."
    },
    {
      "area": "Location data store",
      "evolution_path": "Location Service's write model is behind its own API. Can swap from TimescaleDB to InfluxDB to a custom solution without affecting consumers."
    },
    {
      "area": "Event broker",
      "evolution_path": "Services communicate via a thin event abstraction. Can start with RabbitMQ and migrate to Kafka if throughput demands grow, changing only the infrastructure layer."
    }
  ],

  "rigidity_points": [
    {
      "area": "Order-to-Payment synchronous coupling",
      "reason": "Intentionally rigid. Payment authorization MUST succeed before order confirmation. This coupling reflects a real business invariant — do not attempt to make it eventually consistent."
    },
    {
      "area": "Event schema contracts",
      "reason": "Once published, event schemas become the integration contract. Breaking changes require versioning (e.g., OrderPlacedV2). Invest in schema registry early."
    },
    {
      "area": "Database-per-service boundary",
      "reason": "Once services own their data, you cannot go back to shared DB without re-introducing deployment coupling. This is a one-way door — commit to it fully for each extracted service."
    }
  ],

  "risks": [
    {
      "risk": "Operational overload: 8 engineers operating 6 services with moderate maturity",
      "severity": "high",
      "mitigation": "Phase the extraction. Start with 2 services (Location + Payment) extracted from the monolith. Keep Order, Courier, Customer, and Notification as modules in the monolith for 1-2 quarters. Extract more only when the team has built operational muscle (monitoring, distributed tracing, incident runbooks)."
    },
    {
      "risk": "Distributed transaction failures in order placement (Order + Payment)",
      "severity": "high",
      "mitigation": "Payment auth is synchronous with timeout + circuit breaker. On Payment Service failure: fail the order fast, show clear error to customer. Idempotency keys prevent double-charges on retry. Add dead letter queue for failed compensating actions."
    },
    {
      "risk": "Location Service data loss under peak load (5K writes/sec)",
      "severity": "medium",
      "mitigation": "Use a write-optimized time-series database (TimescaleDB or InfluxDB). Buffer writes through the message broker if needed. Location data is ephemeral — losing a few pings is acceptable; losing all pings for a courier is not. Monitor write latency p99."
    },
    {
      "risk": "Event ordering and duplication causing incorrect state",
      "severity": "medium",
      "mitigation": "All consumers must be idempotent. Use event sequence numbers or timestamps for ordering within a single aggregate. Implement correlation IDs for end-to-end tracing across services."
    },
    {
      "risk": "Data consistency across services for customer-facing queries (e.g., order status page needs data from Order + Courier + Location)",
      "severity": "medium",
      "mitigation": "Build a read-model/BFF (Backend-for-Frontend) that subscribes to events from multiple services and materializes a denormalized view. Do NOT make synchronous fan-out queries to 3 services on every page load."
    },
    {
      "risk": "Team lacks experience with distributed systems debugging",
      "severity": "medium",
      "mitigation": "Invest in observability BEFORE extracting services: distributed tracing (Jaeger/Zipkin), centralized logging (ELK/Datadog), per-service dashboards. This is a prerequisite, not a nice-to-have."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phased Strangler Fig extraction over 3-4 quarters.\n\nPhase 0 (Q1): Prepare the monolith. Introduce clear module boundaries internally. Set up event bus infrastructure (start with RabbitMQ). Add distributed tracing. Define event schemas. This phase produces NO new services — it makes the monolith ready for extraction.\n\nPhase 1 (Q2): Extract Location Service. Highest write volume, most different data model, lowest business logic complexity. Strangler pattern: route GPS pings to new service, keep reads dual-sourced until cutover. Simultaneously extract Payment Service — strict consistency requirements make it the most dangerous to share a deployment with unrelated code.\n\nPhase 2 (Q3): Extract Notification Service (generic, low risk, good operational training). Extract Customer Service if change velocity warrants it.\n\nPhase 3 (Q4): Extract Order and Courier Services last — they are the core domain with the most complex interactions. By now the team has 2-3 quarters of microservices operational experience.",
    "files_to_create_or_modify": [
      "docs/adr/001-service-decomposition.md — Architecture Decision Record capturing this decomposition and rationale",
      "docs/adr/002-event-schema-strategy.md — Event versioning and schema registry approach",
      "docs/context-map.puml — PlantUML diagram of bounded contexts and relationships",
      "infrastructure/docker-compose.yml — Local development environment with all services + broker + tracing",
      "libs/events/schemas/ — Shared event schema definitions (protobuf or JSON Schema)",
      "services/location-service/ — First extracted service (Phase 1)",
      "services/payment-service/ — First extracted service (Phase 1)"
    ],
    "patterns_to_follow": "Strangler Fig for extraction. Database-per-service. Domain events as primary integration. Idempotent consumers. Circuit breakers on synchronous calls. CQRS only for Location Service. Choreography sagas for cross-service workflows (upgrade to orchestration if complexity warrants).",
    "pitfalls_to_avoid": [
      "Do NOT extract all 6 services simultaneously — the team will drown in operational complexity",
      "Do NOT share databases between services — this recreates the deployment coupling you are trying to eliminate",
      "Do NOT build a distributed monolith — if every request requires synchronous calls to 4 services, you have worse coupling than before with added network latency",
      "Do NOT skip the observability investment in Phase 0 — you cannot debug distributed systems with monolith-era tools",
      "Do NOT create a shared 'common' library with business logic — this becomes a stealth coupling vector. Share only schemas and infrastructure concerns",
      "Do NOT use synchronous REST calls between services as the default — prefer async events. Reserve sync calls for cases with genuine consistency requirements (Payment auth)"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 82,
    "high_confidence_areas": [
      "Service boundary decomposition along domain lines — these are natural seams",
      "Location Service extraction priority — clearly different scaling characteristics",
      "Payment Service isolation — strict consistency requirements demand an independent boundary",
      "Phased migration approach — 8 engineers cannot safely operate 6 new services day one"
    ],
    "low_confidence_areas": [
      "Exact Phase 2/3 sequencing — depends on actual team velocity and which parts of the monolith have highest change frequency",
      "Choice of choreography vs orchestration sagas — depends on how complex the order lifecycle actually is in practice (number of compensating actions, edge cases)",
      "Whether Customer Service warrants extraction at all — if it is low-change-velocity CRUD, it may be better left as a module in Order Service"
    ],
    "assumptions": [
      "The 5K writes/sec location load is genuinely sustained peak, not a brief spike — if it is a spike, Location Service may not need a separate time-series DB",
      "The team is willing to invest a full quarter in Phase 0 (observability + internal modularization) before extracting any service",
      "The existing monolith has a reasonably clean data model — if the DB has extensive cross-domain foreign keys and triggers, Phase 0 will take longer",
      "The team has or can acquire basic message broker operational skills (RabbitMQ/Kafka)"
    ]
  }
}
